transcript.content:
[
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "Turns out Adam Smith got it right.",
        "explanation": "The author presents a subjective causal judgment ('got it right') as fact, without explicit attribution, positioning the analysis as uncontested when it is subject to debate."
    },
    {
        "biasType": "Spin",
        "biasedText": "That option coercively redirects money to the government that households would much rather spend or save for other purposes.",
        "explanation": "The use of the word 'coercively' introduces emotional and subjective language that frames the effect of tariffs in a negative light, rather than neutrally describing the situation."
    },
    {
        "biasType": "Spin",
        "biasedText": "The alternative, which may be even worse, is that Americans never get to purchase the imported products they want...",
        "explanation": "The phrase 'which may be even worse' is interpretive and subjective, suggesting a hierarchy of harms that is the author's opinion."
    },
    {
        "biasType": "Spin",
        "biasedText": "the purported free lunch of Trump's tariffs is a farce.",
        "explanation": "Calling the 'free lunch' a 'farce' is sensational and pejorative language, showing spin by using ridicule."
    },
    {
        "biasType": "Spin",
        "biasedText": "The president has completely ignored this data, of course, and is now threatening to punish Americans further by raising taxes on European imports until Denmark agrees to hand over Greenland.",
        "explanation": "The phrase 'completely ignored this data, of course,' assumes intention and dismisses any alternative reasoning. The reference to 'punish Americans further' and the Greenland remark employ sarcasm and exaggeration, contributing to a sarcastic, critical spin."
    },
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "Both buyers and sellers benefit from voluntary economic transactions, so blocking them with tariffs hurts both parties.",
        "explanation": "The author presents a subjective economic theory as uncontested fact without attribution or acknowledgment of debate among economists."
    },
    {
        "biasType": "Opinion Statements Presented as Fact",
        "biasedText": "But while European firms lose revenue from exports, Americans lose both the money they already earned and their choices in how to spend it.",
        "explanation": "The assertion that Americans 'lose both the money they already earned and their choices' is a subjective causal interpretation presented as fact rather than analysis."
    }
]

